import base64
import os

images = {
    "custard_apple.jpg": "data:image/jpeg;base64,",
    "orange.jpg": "data:image/jpeg;base64,",
    "mango.jpg": "data:image/jpeg;base64,",
    "malta.jpg": "data:image/jpeg;base64,",
    "banana.jpg": "data:image/jpeg;base64,",
    "guava.jpg": "data:image/jpeg;base64,",
    "dragon_fruit.jpg": "data:image/jpeg;base64,"
}

os.makedirs("public/images", exist_ok=True)

for filename, data in images.items():
    if data.startswith("data:image"):
        # Remove header
        header, encoded = data.split(",", 1)
        binary_data = base64.b64decode(encoded)
        with open(f"public/images/{filename}", "wb") as f:
            f.write(binary_data)
        print(f"Saved {filename}")

print("All images saved successfully.")
